// ================================================================
// WF1 EXTRACT DATA - VERSION 12.17
// FIX: CC logic - ALWAYS CC to hoangkha, vynnl, and directive source
// SCHEMA VERIFIED: 2025-12-29
// ================================================================

// =========== CONSTANTS ===========
const CLARIFICATIONS_DB_ID = '9abf8678-830d-47d6-9e4f-189a41b28493';
const WF_LOGS_DB_ID = '53a48a4f-29ba-46d2-8e53-3f358d3c513c';

const FORM_BASE_URL = 
  'https://docs.google.com/forms/d/e/1FAIpQLSdzRTOucM4qWwlxyx3yEelDorBv2ADnL8jFUUW7-xpqdidvBw/viewform';

const FORM_ENTRIES = {
  maClarification: '1684171280',
  nguonChiDao: '1878008034',
  ngayNhanChiDao: '1953342780',
  noiDungGoc: '1839616630',
  dauMoiT1: '649583359',
  t2NhiemVu: '1319518938',
  t3ChiTieu: '1910876946',
  t4ThoiHan: '1661283634',
  ghiChu: '1985703119',
  xacNhan: '429936070'
};

// =========== CC CONFIGURATION ===========
// LUÔN CC tới những người này
const ALWAYS_CC_EMAILS = [
  'hoangkha@esuhai.com',
  'vynnl@esuhai.com'
];

// Fallback khi không có email đầu mối
const FALLBACK_SEND_TO = 'vynnl@esuhai.com';

// =========== HELPER FUNCTIONS ===========

function safeText(richTextArray) {
  if (!richTextArray || !Array.isArray(richTextArray)) return '';
  return richTextArray.map(t => t.plain_text || '').join('').trim();
}

function safeDate(dateObj) {
  if (!dateObj || !dateObj.start) return '';
  return dateObj.start;
}

function safeSelect(selectObj) {
  if (!selectObj || !selectObj.name) return '';
  return selectObj.name;
}

function safeTitle(titleArray) {
  if (!titleArray || !Array.isArray(titleArray)) return '';
  return titleArray.map(t => t.plain_text || '').join('').trim();
}

function safeRelationFirst(relationArray) {
  if (!relationArray || !Array.isArray(relationArray) || relationArray.length === 0) return null;
  return relationArray[0].id || null;
}

function safeMultiSelect(multiSelectArray) {
  if (!multiSelectArray || !Array.isArray(multiSelectArray)) return [];
  return multiSelectArray.map(item => item.name || '').filter(Boolean);
}

function safeRollup(rollupObj) {
  if (!rollupObj) return '';
  if (rollupObj.type === 'array' && Array.isArray(rollupObj.array)) {
    const firstItem = rollupObj.array[0];
    if (!firstItem) return '';
    if (firstItem.type === 'email') return firstItem.email || '';
    if (firstItem.type === 'rich_text') return safeText(firstItem.rich_text);
    if (firstItem.type === 'title') return safeTitle(firstItem.title);
  }
  if (rollupObj.type === 'string') return rollupObj.string || '';
  if (rollupObj.type === 'number') return String(rollupObj.number || '');
  return '';
}

function buildPrefillUrl(data) {
  const params = [];
  const mappings = {
    [FORM_ENTRIES.maClarification]: data.maClarification || '',
    [FORM_ENTRIES.nguonChiDao]: data.nguonChiDao || '',
    [FORM_ENTRIES.ngayNhanChiDao]: data.ngayNhanChiDao || '',
    [FORM_ENTRIES.noiDungGoc]: data.noiDungGoc || '',
    [FORM_ENTRIES.dauMoiT1]: data.dauMoiT1 || '',
    [FORM_ENTRIES.t2NhiemVu]: data.t2NhiemVu || '',
    [FORM_ENTRIES.t3ChiTieu]: data.t3ChiTieu || '',
    [FORM_ENTRIES.t4ThoiHan]: data.t4ThoiHan || '',
    [FORM_ENTRIES.ghiChu]: data.ghiChu || '',
    [FORM_ENTRIES.xacNhan]: data.xacNhan || ''
  };
  for (const [entryId, value] of Object.entries(mappings)) {
    if (value) {
      params.push(`entry.${entryId}=${encodeURIComponent(String(value))}`);
    }
  }
  return `${FORM_BASE_URL}?${params.join('&')}`;
}

function formatDateVN(dateStr) {
  if (!dateStr) return '';
  try {
    const d = new Date(dateStr);
    if (isNaN(d.getTime())) return dateStr;
    return `${d.getDate().toString().padStart(2,'0')}/${(d.getMonth()+1).toString().padStart(2,'0')}/${d.getFullYear()}`;
  } catch {
    return dateStr;
  }
}

function truncate(str, maxLen = 100) {
  if (!str) return '';
  if (str.length <= maxLen) return str;
  return str.substring(0, maxLen - 3) + '...';
}

function extractPages(inputItem) {
  const pages = [];
  const json = inputItem.json;

  if (json.properties && json.id) {
    pages.push(json);
    return pages;
  }

  if (json.result?.properties && json.result?.id) {
    pages.push(json.result);
    return pages;
  }

  if (json.results && Array.isArray(json.results)) {
    for (const result of json.results) {
      if (result.properties && result.id) {
        pages.push(result);
      }
    }
    return pages;
  }

  if (json.object === 'list' && json.results) {
    for (const result of json.results) {
      if (result.properties && result.id) {
        pages.push(result);
      }
    }
    return pages;
  }

  return pages;
}

function isClarificationPage(page) {
  if (page.parent?.database_id) {
    const dbId = page.parent.database_id.replace(/-/g, '');
    const clarDbId = CLARIFICATIONS_DB_ID.replace(/-/g, '');
    return dbId === clarDbId;
  }
  return false;
}

/**
 * Build CC list based on business rules
 * @param {string} sendToEmail - Primary recipient
 * @param {string} nguon - Source of directive (CEO, BOD, etc.)
 * @returns {string} Comma-separated CC emails
 */
function buildCcList(sendToEmail, nguon) {
  const ccSet = new Set();

  // 1. LUÔN CC tới hoangkha và vynnl
  for (const email of ALWAYS_CC_EMAILS) {
    // Không CC chính người nhận
    if (email.toLowerCase() !== sendToEmail.toLowerCase()) {
      ccSet.add(email);
    }
  }

  // 2. Nếu nguồn là CEO, có thể thêm email CEO (nếu cần)
  // Hiện tại không có email CEO trong schema
  // Có thể mở rộng sau khi có thêm thông tin

  // 3. Convert Set to comma-separated string
  const ccArray = Array.from(ccSet);
  return ccArray.join(', ');
}

// =========== MAIN PROCESSING ===========

const allItems = $input.all();
const results = [];
let skippedCount = 0;
let processedCount = 0;

// Detect trigger source
let triggerSource = 'Auto';
try {
  const firstItem = allItems[0]?.json;
  if (firstItem?.source) {
    triggerSource = firstItem.source;
  }
} catch (e) {
  triggerSource = 'Auto';
}

console.log(`[v12.17] Processing ${allItems.length} input items`);

for (const item of allItems) {
  try {
    const pages = extractPages(item);

    for (const page of pages) {
      if (!isClarificationPage(page)) {
        skippedCount++;
        continue;
      }

      const props = page.properties;
      const clarificationId = page.id || '';
      const clarificationUrl = page.url || `https://notion.so/${clarificationId.replace(/-/g, '')}`;

      // Extract fields
      const tieuDe = safeTitle(props['Tiêu đề']?.title);
      const tinhTrang = safeSelect(props['Tình trạng']?.select);
      const nguon = safeSelect(props['Nguồn']?.select);
      const ngayNhan = safeDate(props['Ngày nhận']?.date);
      const noiDungGoc = safeText(props['Nội dung gốc']?.rich_text);
      const t1DauMoiRelation = safeRelationFirst(props['T1 - ĐẦU MỐI']?.relation);
      const t2NhiemVu = safeText(props['T2 - NHIỆM VỤ']?.rich_text);
      const t3ChiTieu = safeText(props['T3 - CHỈ TIÊU']?.rich_text);
      const t4ThoiHan = safeDate(props['T4 - THỜI HẠN']?.date);
      const ghiChu = safeText(props['Ghi chú']?.rich_text);
      const emailDauMoiRollup = safeRollup(props['Email đầu mối']?.rollup);
      const thieuYeuTo = safeMultiSelect(props['Thiếu yếu tố nào']?.multi_select);

      // ========================================
      // EMAIL RESOLUTION - NEW LOGIC v12.17
      // ========================================

      // Primary recipient (sendTo)
      let sendToEmail = emailDauMoiRollup;
      let useFallback = false;
      let fallbackReason = '';

      if (!sendToEmail) {
        sendToEmail = FALLBACK_SEND_TO;
        useFallback = true;
        fallbackReason = t1DauMoiRelation 
          ? 'Rollup email trống, có HR relation - cần cập nhật email trong HR' 
          : 'Không có email đầu mối và không có HR relation';
      }

      // CC list - LUÔN có hoangkha và vynnl
      const ccTo = buildCcList(sendToEmail, nguon);

      // ========================================
      // BUILD PREFILL URL
      // ========================================
      const prefillData = {
        maClarification: clarificationId.replace(/-/g, ''),
        nguonChiDao: nguon,
        ngayNhanChiDao: formatDateVN(ngayNhan),
        noiDungGoc: truncate(noiDungGoc, 500),
        dauMoiT1: t1DauMoiRelation ? `[HR:${t1DauMoiRelation.substring(0,8)}]` : '',
        t2NhiemVu: truncate(t2NhiemVu, 300),
        t3ChiTieu: truncate(t3ChiTieu, 300),
        t4ThoiHan: formatDateVN(t4ThoiHan),
        ghiChu: truncate(ghiChu, 200),
        xacNhan: 'Tôi xác nhận thông tin trên là chính xác'
      };

      const prefillUrl = buildPrefillUrl(prefillData);

      // ========================================
      // BUILD EMAIL CONTENT
      // ========================================
      const missingItems = thieuYeuTo.length > 0 ? thieuYeuTo.join(', ') : 'Chưa xác định';
      const emailSubject = `[Cần Làm Rõ] ${truncate(tieuDe, 50)} - Hạn: ${formatDateVN(t4ThoiHan) || 'Chưa xác định'}`;

      const emailBody = `
Kính gửi Anh/Chị phụ trách,

Ban Điều hành cần Anh/Chị xác nhận và bổ sung thông tin cho chỉ đạo sau:

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
📋 CHỈ ĐẠO CẦN LÀM RÕ
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

📌 Tiêu đề: ${tieuDe || '(Chưa có)'}
📅 Ngày nhận: ${formatDateVN(ngayNhan) || 'Chưa xác định'}
🔗 Nguồn: ${nguon || 'Chưa xác định'}

📝 Nội dung gốc:
${noiDungGoc || '(Chưa có nội dung)'}

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
⚠️ THIẾU YẾU TỐ: ${missingItems}
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

✏️ THÔNG TIN CẦN XÁC NHẬN (4T):

👤 T1 - Đầu mối: ${t1DauMoiRelation ? '✓ Đã có' : '❓ Cần xác nhận'}
📋 T2 - Nhiệm vụ: ${t2NhiemVu || '❓ Cần xác nhận'}
🎯 T3 - Chỉ tiêu: ${t3ChiTieu || '❓ Cần xác nhận'}
⏰ T4 - Thời hạn: ${formatDateVN(t4ThoiHan) || '❓ Cần xác nhận'}

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

👉 VUI LÒNG XÁC NHẬN TẠI ĐÂY:
${prefillUrl}

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

⏱️ Thời hạn phản hồi: 24 giờ
📧 Liên hệ hỗ trợ: hoangkha@esuhai.com

Trân trọng,
Ban Thư ký BOD
(Email tự động từ hệ thống ClaudeK)
`.trim();

      // ========================================
      // BUILD RESULT
      // ========================================
      const result = {
        // Core identifiers
        clarificationId,
        clarificationUrl,

        // Extracted data
        tieuDe,
        tinhTrang,
        nguon,
        ngayNhan,
        noiDungGoc,
        t1DauMoiRelation,
        t2NhiemVu,
        t3ChiTieu,
        t4ThoiHan,
        ghiChu,
        thieuYeuTo,

        // ========================================
        // EMAIL CONFIG - v12.17 NEW LOGIC
        // ========================================
        sendTo: sendToEmail,                    // Primary recipient
        ccTo: ccTo,                             // LUÔN có hoangkha, vynnl
        useFallback,
        fallbackReason,

        // Email content
        emailSubject,
        emailBody,

        // Form URL
        prefillUrl,

        // Gmail node compatibility
        triggerSource: triggerSource,
        emailSource: nguon || 'Hệ thống',

        // Metadata
        processedAt: new Date().toISOString(),
        version: '12.17'
      };

      results.push({ json: result });
      processedCount++;
    }

  } catch (error) {
    console.error('[v12.17] Error:', error.message);
    results.push({
      json: {
        error: true,
        errorMessage: error.message,
        triggerSource: 'Error',
        emailSource: 'Error',
        sendTo: FALLBACK_SEND_TO,
        ccTo: ALWAYS_CC_EMAILS.join(', '),
        emailSubject: '[ERROR] Lỗi xử lý chỉ đạo',
        emailBody: `Có lỗi xảy ra: ${error.message}`,
        rawData: item.json
      }
    });
  }
}

console.log(`[v12.17] Done. Processed: ${processedCount}, Skipped: ${skippedCount}`);

if (results.length === 0) {
  return [{
    json: {
      warning: true,
      message: `Không có Clarification nào cần xử lý. Skipped ${skippedCount} items.`,
      triggerSource: 'None',
      emailSource: 'None',
      sendTo: '',
      ccTo: '',
      emailSubject: '',
      emailBody: '',
      version: '12.17'
    }
  }];
}

return results;

